    10→import { SiteHeader } from "@/components/layout/site-header";
    11→import { DecisionBadge } from "@/components/ui/decision-badge";
    12→
    13→interface Project {
    14→    id: string;
    15→    title?: string;
    16→    text: string;
    17→    globalScore?: number;
    18→    recommendation?: string;
    19→    confidenceLevel?: string;
    20→    viabilityScore?: number;
    21→    classification?: string;
    22→    timestamp: string;
    23→    isDemo?: boolean;
    24→    analysis?: any;
    25→}
    26→
    27→function getProjectScore(p: Project): number | undefined {
    28→    return p.globalScore ?? p.viabilityScore;
    29→}
    30→
    31→function getProjectDecision(p: Project): string {
    32→    return p.recommendation ?? p.classification ?? "DRAFT";
    33→}
    34→
    35→function getProjectTitle(p: Project): string {
    36→    return p.title ?? p.text;
    37→}
    38→
    39→export default function WorkspacePage() {
    40→    const { t } = useLanguageStore();
    41→    const [projects, setProjects] = useState<Project[]>([]);
    42→    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    43→    const [searchQuery, setSearchQuery] = useState("");
    44→
    45→    useEffect(() => {
    46→        const currentIdea = localStorage.getItem("k3rn_active_project");
    47→        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");
    48→
    49→        if (currentIdea) {
    50→            const idea = JSON.parse(currentIdea);
    51→            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
    52→            if (!exists) {
    53→                const newProject: Project = {
    54→                    id: idea.id || crypto.randomUUID(),
    55→                    title: idea.title,
    56→                    text: idea.text || "",
    57→                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
    58→                    recommendation: idea.recommendation ?? idea.analysis?.classification,
    59→                    confidenceLevel: idea.confidenceLevel,
    60→                    viabilityScore: idea.viabilityScore ?? idea.analysis?.viabilityScore,
    61→                    classification: idea.classification ?? idea.analysis?.classification,
    62→                    timestamp: idea.timestamp,
    63→                    isDemo: idea.isDemo,
    64→                    analysis: idea.analysis,
    65→                };
    66→                storedProjects.unshift(newProject);
    67→                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
    68→                localStorage.removeItem("k3rn_active_project");
    69→            }
    70→        }
    71→
    72→        if (storedProjects.length === 0) {
    73→            const mocks: Project[] = [
    74→                { id: "1", title: "Drone Fleet SaaS Platform", text: "Plateforme SaaS de gestion de flottes de drones autonomes", globalScore: 82, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date().toISOString(), isDemo: true },
    75→                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true },
    76→                { id: "3", title: "AI Film Script Generator", text: "IA générative pour scripts de films", globalScore: 65, recommendation: "EXPLORE", confidenceLevel: "MEDIUM", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true },
    77→                { id: "4", title: "MeowNet - Social Network for Cats", text: "Réseau social pour chats (MeowNet)", globalScore: 22, recommendation: "PARK", confidenceLevel: "LOW", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true },
    78→            ];
    79→            setProjects(mocks);
    80→        } else {
    81→            setProjects(storedProjects);
    82→        }
    83→    }, []);
    84→
    85→    const filteredProjects = projects.filter(p => {
    86→        const q = searchQuery.toLowerCase();
    87→        return getProjectTitle(p).toLowerCase().includes(q) ||
    88→            p.text.toLowerCase().includes(q) ||
    89→            getProjectDecision(p).toLowerCase().includes(q);
    90→    });
