    92→    return (
    93→        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[#F75105]/30">
    94→            <SiteHeader variant="app" />
    95→
    96→            <main className="pt-28 pb-20 px-6 max-w-[1400px] mx-auto">
    97→
    98→                {/* Page Title & Actions */}
    99→                <div className="flex flex-col md:flex-row justify-between items-end md:items-center gap-8 mb-16">
   100→                    <div>
   101→                        <h1 className="text-[3rem] font-light tracking-[0.05em] leading-none text-white mb-4">
   102→                            Dossiers
   103→                        </h1>
   104→                        <p className="text-[#D2D3D4] font-light text-lg">
   105→                            {projects.length} projets actifs dans votre espace
