   107→                    </div>
   108→
   109→                    <div className="flex items-center gap-4 w-full md:w-auto">
   110→                        <div className="relative flex-1 md:w-80">
   111→                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-[#5D5C5B]" />
   112→                            <Input
   113→                                value={searchQuery}
   114→                                onChange={(e) => setSearchQuery(e.target.value)}
   115→                                placeholder="Rechercher..."
   116→                                className="h-12 pl-12 bg-[--color-bg-card] border-transparent focus:border-[#F75105]/50 focus:ring-[#F75105]/20 rounded-lg text-base text-white placeholder:text-[#5D5C5B] transition-all shadow-sm"
   117→                            />
   118→                        </div>
   119→
   120→                        <div className="flex items-center p-1.5 bg-[--color-bg-card] rounded-lg border border-white/5 h-12">
   121→                            <Button
   122→                                variant="ghost"
   123→                                size="icon"
   124→                                className={cn("h-9 w-9 rounded-md transition-all", viewMode === "grid" ? "bg-[--color-surface-1] text-white shadow-sm" : "text-[#5D5C5B] hover:text-white")}
   125→                                onClick={() => setViewMode("grid")}
   126→                            >
   127→                                <LayoutGrid className="w-5 h-5" />
   128→                            </Button>
   129→                            <Button
   130→                                variant="ghost"
   131→                                size="icon"
   132→                                className={cn("h-9 w-9 rounded-md transition-all", viewMode === "list" ? "bg-[--color-surface-1] text-white shadow-sm" : "text-[#5D5C5B] hover:text-white")}
   133→                                onClick={() => setViewMode("list")}
   134→                            >
   135→                                <ListIcon className="w-5 h-5" />
   136→                            </Button>
   137→                        </div>
   138→                    </div>
   139→                </div>
   140→
   141→                {/* Grid View */}
   142→                {viewMode === "grid" ? (
   143→                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
   144→                        {/* New Project Card */}
   145→                        <Link href="/capture" className="group relative flex flex-col items-center justify-center gap-6 aspect-[4/3] rounded-[24px] border-2 border-dashed border-[--border-default] hover:border-[#F75105]/50 hover:bg-[--color-bg-card]/30 transition-all cursor-pointer">
   146→                            <div className="h-16 w-16 rounded-full bg-[--color-bg-card] flex items-center justify-center group-hover:scale-110 transition-transform group-hover:bg-[#F75105] shadow-lg">
   147→                                <Plus className="w-8 h-8 text-[#D2D3D4] group-hover:text-white transition-colors" />
   148→                            </div>
   149→                            <span className="font-medium text-lg text-[#D2D3D4] group-hover:text-white transition-colors">Nouveau Dossier</span>
   150→                        </Link>
   151→
   152→                        {/* Project Cards */}
   153→                        {filteredProjects.map((project) => {
   154→                            const score = getProjectScore(project);
   155→                            const decision = getProjectDecision(project);
   156→                            const title = getProjectTitle(project);
   157→                            return (
   158→                                <Link href={`/workspace/${project.id}`} key={project.id} className="group relative bg-[--color-bg-card] rounded-[24px] border border-[--border-default] hover:border-[#F75105]/30 shadow-card hover:shadow-[0_0_30px_rgba(247,81,5,0.15)] hover:-translate-y-1 transition-all duration-300 overflow-hidden flex flex-col aspect-[4/3] cursor-pointer">
   159→
   160→                                    {project.isDemo && (
   161→                                        <div className="absolute top-6 right-6 px-3 py-1 rounded-full text-[10px] font-bold bg-[#F75105]/10 text-[#F75105] border border-[#F75105]/20 uppercase tracking-widest z-10">
   162→                                            Simulated
   163→                                        </div>
   164→                                    )}
   165→
   166→                                    <div className="p-8 flex-1 flex flex-col">
   167→                                        <div className="flex justify-between items-start mb-8">
   168→                                            <div className="p-4 bg-background text-[#D2D3D4] rounded-xl group-hover:text-[#F75105] transition-colors border border-white/5">
   169→                                                <Folder className="w-8 h-8" />
   170→                                            </div>
   171→                                            {score !== undefined && (
   172→                                                <div className="flex flex-col items-end pt-2">
   173→                                                    <span className={cn(
   174→                                                        "text-4xl font-light tracking-tighter",
   175→                                                        score >= 70 ? "text-white" : "text-[#5D5C5B]"
   176→                                                    )}>
   177→                                                        {score}
   178→                                                    </span>
   179→                                                </div>
   180→                                            )}
   181→                                        </div>
   182→
   183→                                        <h3 className="text-xl font-medium text-white line-clamp-3 leading-relaxed mb-auto group-hover:text-[#F75105] transition-colors">
   184→                                            {title}
   185→                                        </h3>
   186→
   187→                                        <div className="mt-8 flex items-center justify-between pt-6 border-t border-[--border-default]">
   188→                                            <span className="flex items-center gap-2 text-sm text-[#5D5C5B]">
   189→                                                <Clock className="w-4 h-4" />
   190→                                                {new Date(project.timestamp).toLocaleDateString()}
   191→                                            </span>
   192→                                            <DecisionBadge decision={decision} className="text-[10px] px-3 py-1" />
   193→                                        </div>
   194→                                    </div>
   195→                                </Link>
   196→                            );
   197→                        })}
   198→                    </div>
   199→                ) : (
   200→                    /* List View */
   201→                    <div className="bg-[--color-bg-card] rounded-[24px] border border-[--border-default] overflow-hidden animate-in fade-in shadow-card">
   202→                        {filteredProjects.map((project) => {
   203→                            const score = getProjectScore(project);
   204→                            const decision = getProjectDecision(project);
   205→                            const title = getProjectTitle(project);
   206→                            return (
   207→                                <Link href={`/workspace/${project.id}`} key={project.id} className="flex items-center gap-6 p-6 border-b last:border-0 border-[--border-default] hover:bg-[#2F323A] transition-colors cursor-pointer group">
   208→                                    <div className="p-4 bg-background rounded-xl text-[#D2D3D4] group-hover:text-[#F75105] transition-colors border border-white/5">
   209→                                        <FileBox className="w-6 h-6" />
   210→                                    </div>
   211→                                    <div className="flex-1 min-w-0">
   212→                                        <h4 className="text-lg font-medium text-white truncate group-hover:text-[#F75105] transition-colors mb-2">
   213→                                            {title}
   214→                                        </h4>
   215→                                        <p className="text-sm text-[#5D5C5B] flex items-center gap-3">
   216→                                            {project.isDemo && <span className="text-[#F75105] font-bold text-[10px] uppercase tracking-wider">[Simulated]</span>}
   217→                                            <span className="font-mono text-[#5D5C5B]">ID: {project.id.substring(0, 8)}</span>
   218→                                            <span className="opacity-30">&bull;</span>
   219→                                            <span>{new Date(project.timestamp).toLocaleDateString()}</span>
   220→                                        </p>
   221→                                    </div>
   222→                                    <div className="flex items-center gap-8 pr-4">
   223→                                        {score !== undefined && (
   224→                                            <div className="text-right">
   225→                                                <span className={cn(
   226→                                                    "block text-2xl font-light",
   227→                                                    score >= 70 ? "text-white" : "text-[#5D5C5B]"
   228→                                                )}>{score}</span>
   229→                                            </div>
   230→                                        )}
   231→                                        <DecisionBadge decision={decision} className="min-w-[100px] text-center" />
   232→                                        <Button variant="ghost" size="icon" className="h-10 w-10 text-[#5D5C5B] hover:text-white rounded-full">
   233→                                            <MoreVertical className="w-5 h-5" />
   234→                                        </Button>
   235→                                        <ChevronRight className="w-6 h-6 text-[#5D5C5B] group-hover:text-white transition-colors" />
   236→                                    </div>
   237→                                </Link>
   238→                            );
   239→                        })}
   240→                    </div>
   241→                )}
   242→            </main>
   243→        </div>
